Create a new command that posts the loaded review to GitHub:

1. **Add command registration in package.json**:
   ```json
   {
     "command": "agentReview.postToGitHub",
     "title": "Agent Review: Post to GitHub PR"
   }
   ```

2. **Create new file src/github.ts** for GitHub integration:
   ```typescript
   import * as vscode from 'vscode';
   import { exec } from 'child_process';
   import { promisify } from 'util';
   import { ReviewFile, ReviewComment } from './parser';

   const execAsync = promisify(exec);

   interface GitHubReviewComment {
     path: string;
     line: number;
     side: 'LEFT' | 'RIGHT';
     body: string;
   }

   function mapVerdictToEvent(verdict: string): 'APPROVE' | 'REQUEST_CHANGES' | 'COMMENT' {
     switch (verdict.toUpperCase()) {
       case 'APPROVE': return 'APPROVE';
       case 'REQUEST_CHANGES': return 'REQUEST_CHANGES';
       default: return 'COMMENT';
     }
   }

   function formatCommentBody(comment: ReviewComment): string {
     const severityEmoji: Record<string, string> = {
       blocking: '🚫',
       important: '⚠️',
       suggestion: '💡',
       nit: 'ℹ️',
       praise: '👍',
       learning: '📚'
     };
     const emoji = severityEmoji[comment.severity] || '';
     return `**${comment.severity.toUpperCase()}** ${emoji}\n\n${comment.body}`;
   }

   export async function postReviewToGitHub(review: ReviewFile): Promise<void> {
     // Check gh CLI is available
     try {
       await execAsync('gh --version');
     } catch {
       throw new Error('GitHub CLI (gh) not found. Install from https://cli.github.com/');
     }

     const { repo, number } = review.pr;
     const event = mapVerdictToEvent(review.summary.verdict);
     const body = review.summary.overview;

     // Build review comments for gh api
     const comments: GitHubReviewComment[] = review.comments
       .filter(c => c.severity !== 'praise' && c.severity !== 'learning')
       .map(c => ({
         path: c.path,
         line: c.line,
         side: c.side || 'RIGHT',
         body: formatCommentBody(c)
       }));

     // Use gh api to create review with comments
     const payload = JSON.stringify({
       body,
       event,
       comments
     });

     const cmd = `gh api repos/${repo}/pulls/${number}/reviews -X POST --input -`;
     await execAsync(cmd, { input: payload });
   }
   ```

3. **Register command in extension.ts**:
   ```typescript
   import { postReviewToGitHub } from './github';

   context.subscriptions.push(
     vscode.commands.registerCommand('agentReview.postToGitHub', async () => {
       if (!controller || !controller.review) {
         vscode.window.showWarningMessage('No review loaded');
         return;
       }
       const confirm = await vscode.window.showWarningMessage(
         `Post ${controller.review.comments.length} comments to PR #${controller.review.pr.number}?`,
         'Post Review', 'Cancel'
       );
       if (confirm !== 'Post Review') return;

       try {
         await vscode.window.withProgress(
           { location: vscode.ProgressLocation.Notification, title: 'Posting to GitHub...' },
           () => postReviewToGitHub(controller.review)
         );
         vscode.window.showInformationMessage('Review posted to GitHub!');
       } catch (err) {
         vscode.window.showErrorMessage(`Failed: ${err.message}`);
       }
     })
   );
   ```

