Create a status bar item that displays review status:

1. **Add to extension.ts** - create status bar item in activate():
   ```typescript
   let statusBarItem: vscode.StatusBarItem;

   export function activate(context: vscode.ExtensionContext): void {
     // Create status bar item
     statusBarItem = vscode.window.createStatusBarItem(
       vscode.StatusBarAlignment.Left,
       100
     );
     statusBarItem.command = 'agentReview.reload';
     context.subscriptions.push(statusBarItem);
     // ... rest of activation
   }
   ```

2. **Create updateStatusBar function**:
   ```typescript
   function updateStatusBar(review: ReviewFile | undefined, commentCount: number): void {
     if (!review) {
       statusBarItem.hide();
       return;
     }

     const verdictIcon: Record<string, string> = {
       'APPROVE': '$(check)',
       'REQUEST_CHANGES': '$(x)',
       'COMMENT': '$(comment)'
     };

     const icon = verdictIcon[review.summary.verdict] || '$(comment)';
     statusBarItem.text = `${icon} PR #${review.pr.number} (${commentCount})`;
     statusBarItem.tooltip = `${review.pr.title}\n${review.summary.verdict}\n${commentCount} comments\n\nClick to reload`;
     statusBarItem.show();
   }
   ```

3. **Call updateStatusBar after loading comments** in loadComments():
   ```typescript
   const { loaded, skipped } = controller.loadReview(...);
   updateStatusBar(review, loaded);
   ```

4. **Hide status bar on clear**:
