   context.subscriptions.push(
     vscode.commands.registerCommand('agentReview.clear', () => {
       controller?.clearAll();
       currentFilePath = undefined;
       updateStatusBar(undefined, 0);  // Hide status bar
       vscode.window.showInformationMessage('Agent Review: All comments cleared');
     })
   );
   ```

