Add graceful error handling for JSON parsing failures:

1. **Enhance parseReviewFile in parser.ts**:
   ```typescript
   export async function parseReviewFile(filePath: string): Promise<ReviewFile> {
     const content = await fs.promises.readFile(filePath, 'utf-8');

     let data: unknown;
     try {
       data = JSON.parse(content);
     } catch (e) {
       throw new Error(`Invalid JSON in ${path.basename(filePath)}: ${e.message}`);
     }

     // Validate structure
     if (!data || typeof data !== 'object') {
       throw new Error(`Review file must be a JSON object`);
     }

     const review = data as Record<string, unknown>;

     if (!review.pr || typeof review.pr !== 'object') {
       throw new Error(`Missing or invalid 'pr' field`);
     }

     if (!Array.isArray(review.comments)) {
       throw new Error(`Missing or invalid 'comments' array`);
     }

     // Validate each comment
     for (let i = 0; i < review.comments.length; i++) {
       const c = review.comments[i];
       if (!c.path || typeof c.line !== 'number' || !c.body) {
         throw new Error(`Invalid comment at index ${i}: needs path, line, body`);
       }
       // Default severity if missing
       if (!c.severity) c.severity = 'nit';
       // Default side if missing
       if (!c.side) c.side = 'RIGHT';
     }

     return data as ReviewFile;
   }
   ```

2. **Add backup before save in saveReviewFile**:
   ```typescript
   export async function saveReviewFile(filePath: string, review: ReviewFile): Promise<void> {
     const content = JSON.stringify(review, null, 2);

     // Validate JSON can be re-parsed (sanity check)
     JSON.parse(content);

     await fs.promises.writeFile(filePath, content, 'utf-8');
   }
   ```

