2. **Add command to switch reviews**:
   ```json
   {
     "command": "agentReview.switchReview",
     "title": "Agent Review: Switch Review..."
   }
   ```

3. **Implement review switching**:
   ```typescript
   context.subscriptions.push(
     vscode.commands.registerCommand('agentReview.switchReview', async () => {
       const reviewsDir = getReviewsDir();
       if (!reviewsDir) return;

       const files = await findReviewFiles(reviewsDir);
       if (files.length === 0) {
         vscode.window.showInformationMessage('No review files found');
         return;
       }

       const items = files.map(f => ({
         label: path.basename(f),
         description: f === currentFilePath ? '(current)' : '',
         path: f
       }));

       const selected = await vscode.window.showQuickPick(items, {
         placeHolder: 'Select review to load'
       });

       if (selected) {
         loadComments(selected.path, context.extensionUri);
       }
     })
   );
   ```

